import{_ as r,o as s,c as o,ag as e}from"./chunks/framework.WmBmIPw-.js";const u=JSON.parse('{"title":"启发式算法","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/heuristic-algorithms.md","filePath":"or-opt/heuristic-algorithms.md","lastUpdated":1777116807000}'),n={name:"or-opt/heuristic-algorithms.md"};function i(a,t,g,h,l,c){return s(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="启发式算法" tabindex="-1">启发式算法 <a class="header-anchor" href="#启发式算法" aria-label="Permalink to &quot;启发式算法&quot;">​</a></h1><p>与<a href="./exact-algorithms.html">精确算法</a>相对：<strong>启发式</strong>在可接受计算代价下求<strong>好的可行解</strong>或可行界，<strong>不保证</strong>在有限步内对任意实例证明全局最优（除非在特定结构下可证——那时往往已可纳入精确或近似理论框架讨论）。</p><p>在文献与工程实践中，常把<strong>基于启发式思想的方法</strong>按抽象层次区分为以下三类。本库后续会按子页 <a href="./simple-heuristics.html">基础启发式</a>、<a href="./metaheuristics.html">元启发式</a>、<a href="./hyper-heuristics.html">超启发式</a> 分别展开，此处只作<strong>分类与边界</strong>的梳理，便于对号入座与放置笔记。</p><hr><h2 id="分类总览" tabindex="-1">分类总览 <a class="header-anchor" href="#分类总览" aria-label="Permalink to &quot;分类总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>英文常称</th><th>核心特征（概括）</th></tr></thead><tbody><tr><td><a href="./simple-heuristics.html">基础启发式</a></td><td>simple / constructive / improvement heuristics 等</td><td>面向<strong>具体问题的规则</strong>或<strong>单一路径/邻域</strong>上的构造、贪心、单轮改进等，通常<strong>不</strong>以通用「搜索框架」自称</td></tr><tr><td><a href="./metaheuristics.html">元启发式</a></td><td>metaheuristics</td><td>在解空间上重复迭代的<strong>通用高层框架</strong>（如群体、热力学类比、记忆结构等），与问题建模通过编码与目标函数<strong>接口化</strong></td></tr><tr><td><a href="./hyper-heuristics.html">超启发式</a></td><td>hyper-heuristics</td><td>在<strong>启发式算子/邻域/低层策略</strong>层面做<strong>选择、组合或生成</strong>，强调与问题解表示<strong>解耦</strong>、跨问题可迁移的管理层</td></tr></tbody></table><p>三类的边界并非绝对：元启发式里也可嵌套问题特化算子；超启发式所选对象本身常是<strong>基础启发式</strong>或<strong>小粒度元策略</strong>。写作时以「主要贡献在那一层」为准即可。</p><hr><h2 id="一、基础启发式-simple-heuristics" tabindex="-1">一、基础启发式（Simple Heuristics） <a class="header-anchor" href="#一、基础启发式-simple-heuristics" aria-label="Permalink to &quot;一、基础启发式（Simple Heuristics）&quot;">​</a></h2><ul><li><strong>对象</strong>：<strong>问题结构</strong>上特化的<strong>构造规则、贪心、优先序、一阶段局部搜索</strong>等。</li><li><strong>特点</strong>：实现直接、可解释，常作为<strong>第一解</strong>、<strong>上界/可行解</strong>供精确算法<strong>热启动</strong>或<strong>剪枝</strong>使用；也可在分解法（如列生成/分支定价）中提供<strong>好的初始列</strong>或<strong>子问题解</strong>。</li><li><strong>与元启发式</strong>：不强调<strong>跨多问题的同一套</strong>迭代框架，而是「这个实例上这条规则往往好用」。</li></ul><hr><h2 id="二、元启发式-metaheuristics" tabindex="-1">二、元启发式（Metaheuristics） <a class="header-anchor" href="#二、元启发式-metaheuristics" aria-label="Permalink to &quot;二、元启发式（Metaheuristics）&quot;">​</a></h2><ul><li><strong>对象</strong>：在编码后的解表示上，用<strong>通用迭代机制</strong>在<strong>探索（exploration）</strong> 与<strong>利用（exploitation）</strong> 间平衡。</li><li><strong>代表谱系</strong>（本库会逐步展开，此处仅举例）：<strong>遗传/进化、模拟退火、禁忌搜索、变邻域、粒子群、蚁群、差分进化</strong>等。</li><li><strong>特点</strong>：<strong>问题无关性</strong>强（同框架换编码与适应度即适用多类问题）；<strong>参数与算子</strong>对效果影响大，常与<strong>调参/自适应</strong>、<strong>混合精确子程序</strong>一起出现。</li></ul><hr><h2 id="三、超启发式-hyper-heuristics" tabindex="-1">三、超启发式（Hyper-heuristics） <a class="header-anchor" href="#三、超启发式-hyper-heuristics" aria-label="Permalink to &quot;三、超启发式（Hyper-heuristics）&quot;">​</a></h2><ul><li><strong>对象</strong>：不（主要）在<strong>全解空间</strong>上直接操作，而在<strong>低层启发式/邻域/扰动/交叉算子</strong>的<strong>池</strong>上学习或搜索：何时用哪种算子、以何顺序组合、或生成新低层规则。</li><li><strong>常见分法</strong>（文献中多交叉使用）：<strong>选择型</strong>（基于规则、强化学习、贝叶斯等，从现成算子中选序列）、<strong>生成型</strong>（以语法或学习模型<strong>生成</strong>新的启发式或邻域）等。</li><li><strong>特点</strong>：利于<strong>可迁移、可复现</strong>的「调算法」研究；在大型组合优化、调度、装箱等场景常见。</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>在 <a href="./simple-heuristics.html">基础启发式</a>、<a href="./metaheuristics.html">元启发式</a>、<a href="./hyper-heuristics.html">超启发式</a> 中<strong>逐类补充</strong>算法、伪代码、适用场景与与精确法的协作方式。</li><li>与 <a href="./exact-algorithms.html">精确算法总览</a> 对照：同一问题可写「精确分支定界 + 启发式上界/初始解」的完整工作流说明。</li></ul>',19)])])}const m=r(n,[["render",i]]);export{u as __pageData,m as default};
